import React, { useState } from 'react';

export default function Productos({ productos, setProductos }) {
  const [mostrarForm, setMostrarForm] = useState(false);
  const [nuevo, setNuevo] = useState({ nombre:'', precio:'', categoria:'Comida', emoji:'📦' });

  const categorias = ['Comida','Farmacia','Tienda'];
  const emojis = { Comida:'🍔', Farmacia:'💊', Tienda:'🛒' };

  const agregar = () => {
    if (!nuevo.nombre || !nuevo.precio) return;
    setProductos(prev => [...prev, { id:Date.now(), ...nuevo, precio:Number(nuevo.precio), activo:true, emoji: emojis[nuevo.categoria] }]);
    setNuevo({ nombre:'', precio:'', categoria:'Comida', emoji:'📦' });
    setMostrarForm(false);
  };

  const toggle = (id) => setProductos(prev => prev.map(p => p.id===id ? {...p, activo:!p.activo} : p));

  return (
    <div style={{ padding:'1.5rem' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'1.25rem' }}>
        <h1 style={{ fontSize:20, fontWeight:700 }}>Productos</h1>
        <button onClick={()=>setMostrarForm(true)}
          style={{ padding:'8px 16px', borderRadius:8, border:'none', background:'#2563EB', color:'#fff', fontWeight:600, cursor:'pointer', fontSize:14 }}>
          + Agregar producto
        </button>
      </div>

      {mostrarForm && (
        <div style={{ background:'#fff', borderRadius:12, padding:'1.25rem', marginBottom:'1.25rem', border:'2px solid #2563EB' }}>
          <div style={{ fontWeight:600, marginBottom:'1rem' }}>Nuevo producto</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10, marginBottom:'1rem' }}>
            <input placeholder="Nombre del producto" value={nuevo.nombre} onChange={e=>setNuevo({...nuevo,nombre:e.target.value})}
              style={{ padding:'8px 12px', borderRadius:8, border:'1px solid #E2E8F0', fontSize:14, outline:'none' }} />
            <input placeholder="Precio en Bs." type="number" value={nuevo.precio} onChange={e=>setNuevo({...nuevo,precio:e.target.value})}
              style={{ padding:'8px 12px', borderRadius:8, border:'1px solid #E2E8F0', fontSize:14, outline:'none' }} />
            <select value={nuevo.categoria} onChange={e=>setNuevo({...nuevo,categoria:e.target.value})}
              style={{ padding:'8px 12px', borderRadius:8, border:'1px solid #E2E8F0', fontSize:14, outline:'none' }}>
              {categorias.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <button onClick={agregar} style={{ padding:'8px 20px', borderRadius:8, border:'none', background:'#2563EB', color:'#fff', fontWeight:600, cursor:'pointer', fontSize:14 }}>Guardar</button>
            <button onClick={()=>setMostrarForm(false)} style={{ padding:'8px 16px', borderRadius:8, border:'1px solid #E2E8F0', background:'transparent', cursor:'pointer', fontSize:14 }}>Cancelar</button>
          </div>
        </div>
      )}

      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(200px, 1fr))', gap:12 }}>
        {productos.map(p => (
          <div key={p.id} style={{ background:'#fff', borderRadius:12, padding:'1rem', border:`1px solid ${p.activo?'#E2E8F0':'#F1F5F9'}`, opacity: p.activo?1:0.6 }}>
            <div style={{ fontSize:32, marginBottom:8 }}>{p.emoji}</div>
            <div style={{ fontWeight:600, fontSize:14, marginBottom:4 }}>{p.nombre}</div>
            <div style={{ fontSize:13, color:'#64748B', marginBottom:2 }}>{p.categoria}</div>
            <div style={{ fontSize:16, fontWeight:700, color:'#2563EB', marginBottom:'0.75rem' }}>Bs. {p.precio}</div>
            <button onClick={()=>toggle(p.id)}
              style={{ width:'100%', padding:'6px', borderRadius:6, border:'1px solid #E2E8F0', background: p.activo?'#F0FDF4':'#FEF2F2',
                color: p.activo?'#16A34A':'#DC2626', cursor:'pointer', fontSize:12, fontWeight:500 }}>
              {p.activo ? '✅ Activo' : '❌ Inactivo'}
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
